   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
+  // Check for shift instructions with variable shift amounts, which can cause
+  // legitimate cost model differences due to undefined behavior handling.
+  bool HasVariableShift = any_of(TheLoop->blocks(), [](BasicBlock *BB) {
+    return any_of(*BB, [](Instruction &I) {
+      if (auto *SI = dyn_cast<BinaryOperator>(&I)) {
+        if (SI->getOpcode() == Instruction::Shl ||
+            SI->getOpcode() == Instruction::LShr ||
